fun main() {
    // ---- Safe call operator (?.) ----
    // Calls the method only if the object is not null
    val name: String? = "Kotlin-chan"
    val nullName: String? = null

    println("Name length: ${name?.length}")  // Prints: 12
    println("Null name length: ${nullName?.length}")  // Prints: null

    // ---- Chaining safe calls ----
    data class Address(val city: String)
    data class User(val name: String, val address: Address?)

    val userWithAddress = User("Alice", Address("Tokyo"))
    val userWithoutAddress = User("Bob", null)

    println("Alice's city: ${userWithAddress.address?.city}")  // Tokyo
    println("Bob's city: ${userWithoutAddress.address?.city}")  // null

    // ---- Elvis operator (?:) ----
    // Provides a default value if the expression is null
    val length = nullName?.length ?: 0
    println("Length with Elvis: $length")

    // ---- Elvis with return ----
    fun printCity(user: User) {
        val city = user.address?.city ?: return
        println("City: $city")
    }

    printCity(userWithAddress)   // City: Tokyo
    printCity(userWithoutAddress) // Returns early, nothing printed

    // ---- Elvis with throw ----
    fun getCityOrThrow(user: User): String {
        return user.address?.city ?: throw IllegalArgumentException("Address is null")
    }

    try {
        println(getCityOrThrow(userWithAddress))  // Tokyo
        println(getCityOrThrow(userWithoutAddress)) // Throws exception
    } catch (e: Exception) {
        println("Error: ${e.message}")
    }

    // ---- Safe call with let ----
    val text: String? = "Hello"
    text?.let {
        println("Text is: $it")
        println("Length: ${it.length}")
    }

    // ---- Safe call with Elvis and let ----
    val result = text?.let {
        it.uppercase()
    } ?: "Default"
    println("Result: $result")

    // ---- Null safety in practice ----
    fun safePrint(text: String?) {
        val output = text?.trim()?.takeIf { it.isNotEmpty() } ?: "Empty or null"
        println(output)
    }

    safePrint("  Hello  ")  // Hello
    safePrint("   ")        // Empty or null
    safePrint(null)         // Empty or null
}

