    val user: User? = null
    // Trying to call method on null with safe call
    val name = user?.name  // Returns null, fine

    // Trying to use Elvis on non-nullable type
    val text: String = "Hello"
    val result = text ?: "Default"  // Error!

    // Forgetting that safe call returns nullable
    val length: Int = user?.name?.length  // Error! Nullable cannot be assigned to non-nullable
